function solve(nums: number[], k: number): number {
    const n = nums.length;
    const prefix_xor = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        prefix_xor[i] = prefix_xor[i - 1] ^ nums[i - 1];
    }

    // Initialize DP table
    const dp = new Array(n + 1).fill(0).map(() => new Array(k + 1).fill(0));
    // For j=1, dp[i][1] is prefix_xor[i]
    for (let i = 1; i <= n; i++) {
        dp[i][1] = prefix_xor[i];
    }

    // Fill the DP table
    for (let j = 2; j <= k; j++) {
        for (let i = j; i <= n; i++) {
            // For each possible m, from j-1 to i-1
            let minMax = Infinity;
            for (let m = j - 1; m < i; m++) {
                const current_xor = prefix_xor[i] ^ prefix_xor[m];
                const prevMax = dp[m][j - 1];
                const currentMax = Math.max(prevMax, current_xor);
                if (currentMax < minMax) {
                    minMax = currentMax;
                }
            }
            dp[i][j] = minMax;
        }
    }

    return dp[n][k];
}

